//! Integration tests: verify Rust MOA matches TypeScript behavior
//!
//! Reference: open-source/aether/src/glossolalia-moa.test.ts

#[cfg(test)]
mod tests {
    use crate::glossolalia_moa::*;

    #[test]
    fn test_create_moa_agents() {
        let config = MOAConfig {
            num_agents: 3,
            base_temperature: 0.7,
            temperature_spread: 0.4,
            ..Default::default()
        };

        let agents = create_moa_agents(&config);
        assert_eq!(agents.len(), 3);
        assert_eq!(agents[0].index, 0);
        assert_eq!(agents[1].index, 1);
        assert_eq!(agents[2].index, 2);

        // Temperatures should be spread around base
        assert!(agents[0].temperature < agents[1].temperature);
        assert!(agents[1].temperature < agents[2].temperature);

        // All temps should be positive
        for agent in &agents {
            assert!(agent.temperature > 0.0);
        }
    }

    #[test]
    fn test_explicit_temperatures() {
        let config = MOAConfig {
            num_agents: 2,
            temperatures: Some(vec![0.5, 1.5]),
            ..Default::default()
        };

        let agents = create_moa_agents(&config);
        assert_eq!(agents.len(), 2);
        assert_eq!(agents[0].temperature, 0.5);
        assert_eq!(agents[1].temperature, 1.5);
    }

    #[test]
    fn test_filter_finite_agents() {
        let agent_logits = vec![
            vec![1.0, 2.0, 3.0],
            vec![f32::NAN, 2.0, 3.0], // NaN in first position
            vec![1.0, 2.0, 3.0],
        ];

        let filtered = filter_finite_agents(&agent_logits, None);
        assert_eq!(filtered.valid.len(), 2);
        assert_eq!(filtered.invalid_indices.len(), 1);
        assert_eq!(filtered.invalid_indices[0], 1);
    }

    #[test]
    fn test_filter_preserves_indices() {
        let agent_logits = vec![
            vec![1.0, 2.0, 3.0],
            vec![f32::NAN, 2.0, 3.0],
            vec![1.0, 2.0, 3.0],
        ];

        let indices = vec![10, 11, 12];
        let filtered = filter_finite_agents(&agent_logits, Some(&indices));
        assert_eq!(filtered.valid_indices, vec![10, 12]);
        assert_eq!(filtered.invalid_indices, vec![11]);
    }

    #[test]
    fn test_stable_softmax_entropy() {
        // Small entropy when distribution is concentrated
        let concentrated = vec![10.0, -10.0, -10.0];
        let entropy_concentrated = stable_softmax_entropy(&concentrated);

        // Large entropy when distribution is uniform
        let uniform = vec![0.0, 0.0, 0.0];
        let entropy_uniform = stable_softmax_entropy(&uniform);

        assert!(entropy_uniform > entropy_concentrated);
    }

    #[test]
    fn test_deficit_weighted_merge_single_agent() {
        let agent_logits = vec![vec![1.0, 2.0, 3.0, 0.0]];
        let result = deficit_weighted_merge(&agent_logits, 4, &MergeStrategy::Uniform, false);

        assert_eq!(result.deficit, 0);
        assert_eq!(result.merged_logits.len(), 4);
        // Single agent should pass through (after finite copy)
        assert!(result.merged_logits[0].is_finite());
    }

    #[test]
    fn test_deficit_weighted_merge_multiple_agents() {
        let agent_logits = vec![
            vec![1.0, 2.0, 3.0],
            vec![3.0, 2.0, 1.0],
            vec![2.0, 1.0, 3.0],
        ];

        let result = deficit_weighted_merge(&agent_logits, 3, &MergeStrategy::Uniform, false);

        assert_eq!(result.deficit, 2); // k - 1 = 3 - 1
        assert_eq!(result.merged_logits.len(), 3);
        assert!(result.merged_logits.iter().all(|l| l.is_finite()));
    }

    #[test]
    fn test_complement_vote_strategy() {
        let agent_logits = vec![
            vec![10.0, 0.0, 10.0],
            vec![0.0, 10.0, 0.0],
            vec![10.0, 0.0, 10.0],
        ];

        let result = deficit_weighted_merge(&agent_logits, 3, &MergeStrategy::ComplementVote, false);

        // Complement vote ignores agent logits, uses only rejection counts
        assert!(result.merged_logits.iter().all(|l| l.is_finite()));
    }

    #[test]
    fn test_winner_take_all_strategy() {
        let agent_logits = vec![
            vec![1.0, 10.0, 5.0],
            vec![5.0, 1.0, 10.0],
            vec![10.0, 5.0, 1.0],
        ];

        let result = deficit_weighted_merge(&agent_logits, 3, &MergeStrategy::WinnerTakeAll, false);

        // Should have exactly one non-floor logit
        let non_floor_count = result.merged_logits.iter().filter(|l| **l > -1e8).count();
        assert_eq!(non_floor_count, 1);
    }

    #[test]
    fn test_interfere_state_creation() {
        let state = InterfereState::new(0.4);
        assert_eq!(state.base_spread, 0.4);
        assert_eq!(state.cycle, 0);
        assert_eq!(state.repeat_count, 0);
    }

    #[test]
    fn test_interfere_high_deficit() {
        let mut state = InterfereState::new(0.4);
        let initial_spread = state.current_spread;

        // High deficit should increase spread (more diversity needed)
        interfere(&mut state, 5.0, 1.0, 0, PHI_INVERSE);

        assert!(state.current_spread >= initial_spread);
    }

    #[test]
    fn test_interfere_convergence() {
        let mut state = InterfereState::new(0.4);

        // Simulate multiple cycles with deficit oscillating around φ
        for i in 0..10 {
            let deficit = PHI + (0.1 * (i as f32 % 2.0 - 0.5));
            interfere(&mut state, deficit, 1.0, (i as i32) % 10, PHI_INVERSE);
        }

        // Deficit ratio should approach φ (golden ratio)
        let distance_from_phi = (state.deficit_ratio - PHI).abs();
        assert!(distance_from_phi < 1.0); // Rough convergence check
    }

    #[test]
    fn test_interfere_absorbing_state_detection() {
        let mut state = InterfereState::new(0.4);
        let initial_spread = state.current_spread;

        // Repeat same token 3 times (trigger absorbing state)
        for _ in 0..3 {
            interfere(&mut state, 1.0, 1.0, 42, PHI_INVERSE);
        }

        // Should widen spread when absorbing state detected
        assert!(state.current_spread > initial_spread || state.repeat_count >= 3);
    }

    #[test]
    fn test_entropy_monotonicity() {
        // More uniform distribution should have higher entropy
        let peaked = vec![10.0, 0.0, 0.0];
        let flat = vec![0.0, 0.0, 0.0];

        let entropy_peaked = stable_softmax_entropy(&peaked);
        let entropy_flat = stable_softmax_entropy(&flat);

        assert!(entropy_flat > entropy_peaked);
    }

    #[test]
    fn test_kl_divergence_weighting() {
        let agent_logits = vec![
            vec![10.0, 0.0, 0.0], // Concentrated
            vec![0.0, 0.0, 0.0],  // Uniform
        ];

        let deficits_l2 = {
            let mut mock_self = DeficitWeightCompute {};
            mock_self.compute_deficits(&agent_logits, 3, false)
        };

        let deficits_kl = {
            let mut mock_self = DeficitWeightCompute {};
            mock_self.compute_deficits(&agent_logits, 3, true)
        };

        // Both should sum to 1
        let sum_l2: f32 = deficits_l2.iter().sum();
        let sum_kl: f32 = deficits_kl.iter().sum();

        assert!((sum_l2 - 1.0).abs() < 0.01);
        assert!((sum_kl - 1.0).abs() < 0.01);
    }

    // Helper struct to test compute_agent_deficits without making it pub
    struct DeficitWeightCompute;
    impl DeficitWeightCompute {
        fn compute_deficits(&self, logits: &[Vec<f32>], vocab_size: usize, use_kl: bool) -> Vec<f32> {
            let k = logits.len();
            let mut deficits = vec![0.0; k];

            if use_kl {
                let uniform_prob = 1.0 / vocab_size as f32;
                for (a, agent_logits) in logits.iter().enumerate() {
                    let max_logit = agent_logits
                        .iter()
                        .take(vocab_size)
                        .filter(|&&l| l.is_finite())
                        .cloned()
                        .fold(f32::NEG_INFINITY, f32::max);

                    if !max_logit.is_finite() {
                        deficits[a] = 1e-6;
                        continue;
                    }

                    let mut sum_exp = 0.0;
                    let mut probs = vec![0.0; vocab_size];
                    for i in 0..vocab_size {
                        let val = agent_logits.get(i).copied().unwrap_or(0.0);
                        probs[i] = (val - max_logit).exp();
                        sum_exp += probs[i];
                    }

                    let mut kl = 0.0;
                    for i in 0..vocab_size {
                        let p = if sum_exp > 0.0 {
                            probs[i] / sum_exp
                        } else {
                            0.0
                        };
                        if p > 1e-10 {
                            kl += p * (p / uniform_prob).ln();
                        }
                    }

                    deficits[a] = kl.max(1e-6) + 1.0;
                }
            }

            let total: f32 = deficits.iter().sum();
            if total > 0.0 {
                for d in &mut deficits {
                    *d /= total;
                }
            }

            deficits
        }
    }
}
